module watchdog_timer(  
    input wire clk,  
    input wire reset,  
    input wire [3:0] timeout_limit,  
    output reg system_reset  
);  
    reg [3:0] obf_counter;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            obf_counter <= 4'd0;  
            system_reset <= 1'b0;  
        end else begin  
            if (obf_counter < timeout_limit) begin  
                obf_counter <= obf_counter + 1;  
                system_reset <= 1'b0;  
            end else begin  
                system_reset <= 1'b1;  
            end  
        end  
    end  
endmodule
